from collections import OrderedDict
import os

class IndexCache:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache = OrderedDict()

    def get(self, key):
        if key in self.cache:
            value, timestamp = self.cache[key]
            if timestamp < os.path.getmtime(self.index_file_path):
                # If the index file has changed, remove the key from the cache
                del self.cache[key]
                return None
            return value
        return None

    def set(self, key, value):
        if key in self.cache:
            del self.cache[key]
        self.cache[key] = (value, os.path.getmtime(self.index_file_path))

    def delete(self, key):
        if key in self.cache:
            del self.cache[key]

    def clear(self):
        self.cache.clear()

